def get_hwid():
    try:
        output = subprocess.check_output("wmic csproduct get uuid", shell=True).decode(errors="ignore").splitlines()
        for line in output:
            line = line.strip()
            if line and line != "UUID":
                return line
    except:
        pass
    return str(uuid.getnode())

LOGO_B64 = ""
def verify_key_local(key: str):
    try:
        decoded = base64.urlsafe_b64decode(key.strip().encode())
        parts = decoded.split(b"|")
        if len(parts) < 2:
            return False, "Invalid key", 0
        expiry_bytes = parts[0]
        expiry = datetime.date.fromisoformat(expiry_bytes.decode())
        days_left = (expiry - datetime.date.today()).days
        if days_left < 0:
            return False, expiry.isoformat(), days_left
        return True, expiry.isoformat(), days_left
    except Exception:
        return False, "Invalid key", 0

def check_banned_online(key: str):
    try:
        payload = {"key": key, "hwid": get_hwid()}
        r = requests.post(f"{PANEL_URL}/verify", json=payload, timeout=5)
        if r.status_code == 200:
            data = r.json()
            if not data.get("found", False):
                return True, "Key not found"
            if data.get("expired", False):
                return True, "Key expired"
            if data.get("banned", False):
                return True, "Key banned"
            if not data.get("hwid_ok", True):
                return True, "HWID mismatch"
            return False, ""
    except Exception as e:
        return True, f"Server error: {e}"
    return True, "Auth check failed"


def check_banned_online(key: str):
    try:
        payload = {"key": key, "hwid": get_hwid()}
        r = requests.post(f"{PANEL_URL}/verify", json=payload, timeout=3)
        if r.status_code == 200:
            data = r.json()
            if not data.get("found", False):
                return True, "Key not found"
            if data.get("expired", False):
                return True, "Key expired (server)"
            if data.get("banned", False):
                return True, "Key banned"
            if not data.get("hwid_ok", True):
                return True, "HWID mismatch"
            return False, ""
    except Exception:
        return True, "Auth server error"
    return True, "Auth check failed"

def load_saved_key():
    if os.path.exists(KEY_FILE):
        with open(KEY_FILE) as f:
            return f.read().strip()
    return ""

def save_key(key: str):
    with open(KEY_FILE, "w") as f:
        f.write(key.strip())

def styled_entry(parent, textvariable, width=38, show=None):
    e = tk.Entry(parent, textvariable=textvariable, width=width,
                 bg=BG3, fg=FG, insertbackground=ACCENT2,
                 relief="flat", font=("Segoe UI", 10),
                 highlightthickness=1, highlightbackground=BORDER,
                 highlightcolor=ACCENT, bd=0,
                 **({"show": show} if show else {}))
    return e

def styled_btn(parent, text, command, w=14, color=None, fg=None):
    return tk.Button(parent, text=text, command=command, width=w,
                     bg=color or ACCENT, fg=fg or "#ffffff",
                     activebackground=ACCENT2,
                     activeforeground="#fff", relief="flat",
                     font=("Segoe UI", 10, "bold"), bd=0,
                     cursor="hand2", pady=6)

def load_logo(size=100):
    try:
        data = base64.b64decode(LOGO_B64)
        img  = Image.open(io.BytesIO(data)).resize((size, size), Image.LANCZOS)
        return ImageTk.PhotoImage(img)
    except:
        return None

def show_license_window():
    valid_result = {"ok": False}
    win = tk.Tk()
    win.title("Yariz Recoil")
    win.geometry("460x320")
    win.resizable(False, False)
    win.configure(bg=BG)
    try:
        win.iconbitmap("yarizs.ico")
    except Exception:
        pass
    win.update()
    set_dark_titlebar(win)
    logo_img = load_logo(90)
    if logo_img:
        lbl_logo = tk.Label(win, image=logo_img, bg=BG)
        lbl_logo.image = logo_img
        lbl_logo.pack(pady=(14, 4))
    tk.Label(win, text="Yariz Recoil", font=("Segoe UI", 16, "bold"),
             bg=BG, fg=ACCENT2).pack()
    tk.Label(win, text="Enter your license key", font=("Segoe UI", 9),
             bg=BG, fg=FG2).pack(pady=(2, 10))
    key_var = tk.StringVar()
    entry = styled_entry(win, key_var, width=44)
    entry.pack(ipady=6, padx=30)
    entry.focus()
    status_lbl = tk.Label(win, text="", font=("Segoe UI", 9), bg=BG, fg=RED)
    status_lbl.pack(pady=4)

    def do_login():
        key = key_var.get().strip()
        valid, expiry, days_left = verify_key_local(key)
        if not valid:
            lbl = f"Key expired on {expiry}." if days_left < 0 else "Invalid key."
            status_lbl.config(text=lbl, fg=RED)
            return
        status_lbl.config(text="Verifying online...", fg=FG2)
        win.update()
        banned, reason = check_banned_online(key)
        if banned:
            status_lbl.config(text=reason or "Key rejected by server.", fg=RED)
            return
        save_key(key)
        valid_result["ok"] = True
        status_lbl.config(text=f"Valid — expires {expiry} ({days_left}d left)", fg=GREEN)
        win.after(700, win.destroy)

    btn = styled_btn(win, "Login", do_login, w=16)
    btn.pack(pady=8)
    win.bind("<Return>", lambda e: do_login())
    win.mainloop()
    return valid_result["ok"]

def load_all_configs():
    c = configparser.ConfigParser()
    if os.path.exists(CONFIG_FILE):
        c.read(CONFIG_FILE)
    configs = {}
    for section in c.sections():
        try:
            x = max(-20.0, min(float(c[section].get("X", "0.0")), 20.0))
            y = max(0.0,   min(float(c[section].get("Y", "5.0")), 20.0))
            configs[section] = (x, y)
        except:
            pass
    return configs

def save_all_configs(configs):
    c = configparser.ConfigParser()
    for name, (x, y) in configs.items():
        c[name] = {"X": str(round(x, 1)), "Y": str(round(y, 1))}
    with open(CONFIG_FILE, "w") as f:
        c.write(f)

def is_pressed():
    l = win32api.GetAsyncKeyState(win32con.VK_LBUTTON) & 0x8000
    r = win32api.GetAsyncKeyState(win32con.VK_RBUTTON) & 0x8000
    return l and r

def move_loop(get_x, get_y):
    global running, accumulator_x, accumulator_y
    while running:
        if is_pressed():
            accumulator_x += get_x()
            accumulator_y += get_y()
            mx = int(accumulator_x)
            my = int(accumulator_y)
            if mx or my:
                pydirectinput.move(mx, my, relative=True)
                accumulator_x -= mx
                accumulator_y -= my
        else:
            accumulator_x = 0.0
            accumulator_y = 0.0
        time.sleep(0.01)

def set_dark_titlebar(window):
    try:
        import ctypes
        hwnd = ctypes.windll.user32.GetParent(window.winfo_id())
        if not hwnd:
            hwnd = window.winfo_id()
        DWMWA_USE_IMMERSIVE_DARK_MODE = 20
        ctypes.windll.dwmapi.DwmSetWindowAttribute(
            hwnd, DWMWA_USE_IMMERSIVE_DARK_MODE,
            ctypes.byref(ctypes.c_int(1)), ctypes.sizeof(ctypes.c_int))
    except Exception:
        pass

def style_notebook(root):
    style = ttk.Style(root)
    style.theme_use("default")
    style.configure("TNotebook", background=BG, borderwidth=0)
    style.configure("TNotebook.Tab", background=BG2, foreground=FG2,
                    padding=(12, 6), font=("Segoe UI", 9, "bold"))
    style.map("TNotebook.Tab",
              background=[("selected", BG3)],
              foreground=[("selected", ACCENT2)])

def build_recoil_tab(frame, configs, xv, yv):
    slider_frame = tk.Frame(frame, bg=BG2, padx=20, pady=16)
    slider_frame.pack(fill="x", padx=14, pady=(12, 0))

    row_x = tk.Frame(slider_frame, bg=BG2)
    row_x.pack(fill="x", pady=4)
    tk.Label(row_x, text="X", bg=BG2, fg=ACCENT, font=("Segoe UI", 12, "bold"), width=2).pack(side="left")
    lx = tk.Label(row_x, text="0.0", bg=BG2, fg=ACCENT2, font=("Segoe UI", 10, "bold"), width=5, anchor="e")
    def ux(v): lx.config(text=f"{float(v):.1f}")
    sx = tk.Scale(row_x, from_=-20.0, to=20.0, resolution=0.1,
                  orient="horizontal", length=390, variable=xv, command=ux,
                  showvalue=False, bg=BG2, fg=ACCENT, activebackground=ACCENT2,
                  troughcolor=BG3, highlightthickness=0, bd=0, sliderrelief="flat")
    sx.pack(side="left", padx=6, fill="x", expand=True)
    lx.pack(side="left")

    row_y = tk.Frame(slider_frame, bg=BG2)
    row_y.pack(fill="x", pady=4)
    tk.Label(row_y, text="Y", bg=BG2, fg=ACCENT, font=("Segoe UI", 12, "bold"), width=2).pack(side="left")
    ly = tk.Label(row_y, text="5.0", bg=BG2, fg=ACCENT2, font=("Segoe UI", 10, "bold"), width=5, anchor="e")
    def uy(v): ly.config(text=f"{float(v):.1f}")
    sy = tk.Scale(row_y, from_=0.0, to=20.0, resolution=0.1,
                  orient="horizontal", length=390, variable=yv, command=uy,
                  showvalue=False, bg=BG2, fg=ACCENT, activebackground=ACCENT2,
                  troughcolor=BG3, highlightthickness=0, bd=0, sliderrelief="flat")
    sy.pack(side="left", padx=6, fill="x", expand=True)
    ly.pack(side="left")

    cfg_frame = tk.Frame(frame, bg=BG, padx=14, pady=10)
    cfg_frame.pack(fill="both", expand=True)
    tk.Label(cfg_frame, text="Config Name", bg=BG, fg=FG2,
             font=("Segoe UI", 9)).grid(row=0, column=0, sticky="w", pady=(0, 4))
    name_var = tk.StringVar()
    name_entry = tk.Entry(cfg_frame, textvariable=name_var, width=22,
                          bg=BG3, fg=FG, insertbackground=ACCENT2,
                          relief="flat", font=("Segoe UI", 10),
                          highlightthickness=1, highlightbackground=BORDER,
                          highlightcolor=ACCENT, bd=0)
    name_entry.grid(row=1, column=0, ipady=5, sticky="w")

    def btn(parent, text, cmd, w=8, color=ACCENT):
        return tk.Button(parent, text=text, command=cmd, width=w,
                         bg=color, fg="#fff", activebackground=ACCENT2,
                         activeforeground="#fff", relief="flat",
                         font=("Segoe UI", 9, "bold"), bd=0,
                         cursor="hand2", pady=5)

    btn_frame = tk.Frame(cfg_frame, bg=BG)
    btn_frame.grid(row=1, column=1, padx=(8, 0), sticky="w")
    lb_frame = tk.Frame(cfg_frame, bg=BG)
    lb_frame.grid(row=2, column=0, columnspan=2, pady=(10, 0), sticky="ew")
    listbox = tk.Listbox(lb_frame, font=("Courier New", 10), height=7,
                         bg=BG3, fg=FG, selectbackground=ACCENT,
                         selectforeground="#fff", relief="flat",
                         highlightthickness=1, highlightbackground=BORDER,
                         activestyle="none", bd=0)
    listbox.pack(side="left", fill="both", expand=True)
    sb = tk.Scrollbar(lb_frame, orient="vertical", command=listbox.yview)
    sb.pack(side="right", fill="y")
    listbox.config(yscrollcommand=sb.set)

    def refresh_list():
        listbox.delete(0, tk.END)
        for name, (x, y) in configs.items():
            listbox.insert(tk.END, f"  {name:<20}  X:{x:>5}   Y:{y:>5}")

    def save_config():
        name = name_var.get().strip()
        if not name:
            messagebox.showwarning("Warning", "Enter a config name.")
            return
        configs[name] = (round(xv.get(), 1), round(yv.get(), 1))
        save_all_configs(configs)
        refresh_list()

    def load_config():
        sel = listbox.curselection()
        if not sel:
            messagebox.showwarning("Warning", "Select a config first.")
            return
        name = list(configs.keys())[sel[0]]
        x, y = configs[name]
        xv.set(x)
        yv.set(y)
        ux(x)
        uy(y)
        name_var.set(name)

    def delete_config():
        sel = listbox.curselection()
        if not sel:
            return
        name = list(configs.keys())[sel[0]]
        del configs[name]
        save_all_configs(configs)
        refresh_list()

    btn(btn_frame, "Save",   save_config).pack(side="left", padx=2)
    btn(btn_frame, "Load",   load_config).pack(side="left", padx=2)
    btn(btn_frame, "Delete", delete_config, color="#6a0030").pack(side="left", padx=2)
    refresh_list()

def build_anti_afk_tab(frame):
    afk_frame = tk.Frame(frame, bg=BG2, padx=20, pady=20)
    afk_frame.pack(fill="x", padx=14, pady=14)

    afk_active = {"on": False}
    tk.Label(afk_frame, text="Anti-AFK", bg=BG2, fg=FG,
             font=("Segoe UI", 11, "bold")).pack(side="left")

    afk_status = tk.Label(afk_frame, text="OFF", bg=BG2, fg=RED,
                          font=("Segoe UI", 9, "bold"), width=4)
    afk_status.pack(side="left", padx=10)

    def toggle_afk():
        afk_active["on"] = not afk_active["on"]
        if afk_active["on"]:
            afk_btn.config(text="Anti-AFK: ON", bg=ACCENT2, fg="#000000")
            afk_status.config(text="ON", fg=GREEN)
        else:
            afk_btn.config(text="Anti-AFK: OFF", bg=ACCENT, fg="#ffffff")
            afk_status.config(text="OFF", fg=RED)

    afk_btn = tk.Button(afk_frame, text="Anti-AFK: OFF", command=toggle_afk,
                        width=16, bg=ACCENT, fg="#ffffff",
                        activebackground=ACCENT2, activeforeground="#fff",
                        relief="flat", font=("Segoe UI", 9, "bold"),
                        bd=0, cursor="hand2", pady=6)
    afk_btn.pack(side="left", padx=(10, 0))

    def afk_loop():
        while running:
            if afk_active["on"]:
                pydirectinput.keyDown("w")
                for _ in range(20):
                    if not afk_active["on"]:
                        break
                    time.sleep(0.1)
                pydirectinput.keyUp("w")
                if not afk_active["on"]:
                    continue
                time.sleep(0.2)
                pydirectinput.keyDown("s")
                for _ in range(20):
                    if not afk_active["on"]:
                        break
                    time.sleep(0.1)
                pydirectinput.keyUp("s")
                time.sleep(0.2)
            else:
                time.sleep(0.1)

    threading.Thread(target=afk_loop, daemon=True).start()

def start_snow(canvas, width, height, flakes_count=40):
    flakes = []
    for _ in range(flakes_count):
        x = random.randint(0, width)
        y = random.randint(0, height)
        r = random.randint(2, 4)
        speed = random.uniform(0.5, 1.5)
        dx = random.uniform(-0.3, 0.3)
        oid = canvas.create_oval(x-r, y-r, x+r, y+r, fill="#ffffff", outline="")
        flakes.append({"id": oid, "x": x, "y": y, "r": r, "dy": speed, "dx": dx})

    def animate():
        if not running:
            return
        for f in flakes:
            f["y"] += f["dy"]
            f["x"] += f["dx"]
            if f["y"] > height + 5:
                f["y"] = -5
                f["x"] = random.randint(0, width)
            canvas.coords(f["id"], f["x"]-f["r"], f["y"]-f["r"], f["x"]+f["r"], f["y"]+f["r"])
        canvas.after(40, animate)

    animate()

def main():
    global running
    if not show_license_window():
        sys.exit(0)
    configs = load_all_configs()
    root = tk.Tk()
    root.title("Yariz Recoil")
    root.geometry("640x540")
    root.resizable(False, False)
    root.configure(bg=BG)
    try:
        root.iconbitmap("yarizs.ico")
    except Exception:
        pass
    root.update()
    set_dark_titlebar(root)
    style_notebook(root)

    main_frame = tk.Frame(root, bg=BG)
    main_frame.pack(fill="both", expand=True)

    canvas = tk.Canvas(main_frame, bg=BG, highlightthickness=0, bd=0)
    canvas.pack(fill="both", expand=True)

    content = tk.Frame(canvas, bg=BG)
    canvas_window = canvas.create_window(0, 0, anchor="nw", window=content)

    def on_configure(event):
        canvas.itemconfig(canvas_window, width=event.width, height=event.height)
    canvas.bind("<Configure>", on_configure)

    header = tk.Frame(content, bg=BG2, pady=10)
    header.pack(fill="x")
    logo_img2 = load_logo(48)
    if logo_img2:
        lbl_logo2 = tk.Label(header, image=logo_img2, bg=BG2)
        lbl_logo2.image = logo_img2
        lbl_logo2.pack(side="left", padx=(16, 10))
    title_frame = tk.Frame(header, bg=BG2)
    title_frame.pack(side="left")
    tk.Label(title_frame, text="Yariz Recoil", font=("Segoe UI", 15, "bold"),
             bg=BG2, fg=ACCENT2).pack(anchor="w")
    saved_key = load_saved_key()
    _, expiry, days_left = verify_key_local(saved_key)
    exp_color = GREEN if isinstance(days_left, int) and days_left > 3 else RED
    day_str = f"{days_left}d left" if isinstance(days_left, int) and days_left != 1 else "1 day left"
    tk.Label(title_frame, text=day_str,
             font=("Segoe UI", 8), bg=BG2, fg=exp_color).pack(anchor="w")

    notebook = ttk.Notebook(content, style="TNotebook")
    notebook.pack(fill="both", expand=True, padx=12, pady=(12, 4))

    recoil_tab = tk.Frame(notebook, bg=BG)
    anti_tab   = tk.Frame(notebook, bg=BG)

    notebook.add(recoil_tab, text="Recoil")
    notebook.add(anti_tab,   text="Anti AFK")

    xv = tk.DoubleVar(value=0.0)
    yv = tk.DoubleVar(value=5.0)

    build_recoil_tab(recoil_tab, configs, xv, yv)
    build_anti_afk_tab(anti_tab)

    footer = tk.Frame(content, bg=BG)
    footer.pack(fill="x", side="bottom")
    sig = tk.Label(footer, text="skidded by Vxenless", bg=BG, fg=FG2,
                   font=("Segoe UI", 8, "italic"))
    sig.pack(side="right", padx=10, pady=(0, 6))

    width = root.winfo_width() or 640
    height = root.winfo_height() or 540
    start_snow(canvas, width, height, flakes_count=40)

    def on_close():
        global running
        running = False
        root.destroy()

    threading.Thread(target=move_loop, args=(xv.get, yv.get), daemon=True).start()
    root.protocol("WM_DELETE_WINDOW", on_close)
    root.mainloop()

if __name__ == "__main__":
    main()
